class Solution:
    def longestSemiRepetitiveSubstring(self, s: str) -> int:
        max_len = 1
        left = 0
        duplicate_count = 0

        for right in range(1, len(s)):
            if s[right] == s[right - 1]:
                duplicate_count += 1

            # If more than one duplicate pair, move left pointer
            while duplicate_count > 1:
                if s[left] == s[left + 1]:
                    duplicate_count -= 1
                left += 1

            max_len = max(max_len, right - left + 1)

        return max_len
